
import _ from 'lodash';
import { CARD } from '@/interface/card';
import { property } from '@/data/constans';

const withoutPlus = [
  property.fu_jia_shang_hai,
  property.ji_neng_duo_shan,
  property.ji_neng_ming_zhong,
  property.jian_bao_ji,
  property.jian_bao_shang,
  property.fu_jia_shang_hai,
];

const needPercent = [
  property.bao_ji_lv,
  property.bao_ji_shang_hai,
  property.yu_xian,
  property.yu_mo,
  property.yu_fo,
  property.ke_xian,
  property.ke_mo,
  property.ke_fo,
  property.du_ling_shu_xing,
  property.jian_bao_ji,
  property.jian_bao_shang,
  property.jian_mian,
  property.wu_shi,
  property.xiu_wei,
];

const keepTwoDecimals = [
  ...needPercent,
  property.ji_neng_duo_shan,
  property.ji_neng_ming_zhong,
];

export const handlePlus = (type: string) => (_.indexOf(withoutPlus, type) > -1 ? '' : ' +');

export const handlePercent = (type: string) => (_.indexOf(needPercent, type) > -1 ? '%' : '');

export const handleDecimals = (type: string, value: number) =>
  (_.indexOf(keepTwoDecimals, type) > -1 ? value.toFixed(2) : value);

export const formatStr = (typeStr: string, value: number) =>
  `${typeStr}${handlePlus(typeStr)} ${handleDecimals(typeStr, value)}${handlePercent(typeStr)}`;

export const currentCard = (currentData: any, num: number) => {
  let rwValue = [];
  let fbValue = '';
  let renXiu = 1;
  let renDu = 0;
  let renJu = 0;
  let faXiu = 1;
  let faDu = 0;
  let faJu = 0;
  let rwChecked = false;
  let fbChecked = false;
  const rwCard = _.find(currentData[num], { type: '人物' });
  if (rwCard) {
    rwValue = [rwCard.character, rwCard.name];
    renXiu = rwCard.levelXiu;
    renDu = rwCard.levelDu;
    renJu = rwCard.levelJu;
    rwChecked = rwCard.juChecked;
  }

  const fbCard = _.find(currentData[num], { type: '法宝' });
  if (fbCard) {
    fbValue = fbCard.name;
    faXiu = fbCard.levelXiu;
    faDu = fbCard.levelDu;
    faJu = fbCard.levelJu;
    fbChecked = fbCard.juChecked;
  }
  return {
    rwValue,
    fbValue,
    renXiu,
    renDu,
    renJu,
    rwChecked,
    faXiu,
    faDu,
    faJu,
    fbChecked,
  };
};
